return [{
  json: {
    workflow_id: 'CWF-130',
    vein: 'scoring_vein',
    dossier_id: $json.dossier_id || 'TEST-DOSSIER',
    qualified_candidates: $json.qualified_candidates || [],
    route_id: $json.route_id || 'ROUTE_PHASE1_STANDARD',
    execution_timestamp: new Date().toISOString(),
    score_dimensions: ['trend_strength', 'search_demand', 'content_gap', 'audience_pain_match', 'longevity', 'governance_risk', 'budget_fit']
  }
}];

const candidates = $json.qualified_candidates || [];
const scored_candidates = candidates.map(c => {
  const scores = {
    trend_strength: c.trend === 'RISING' ? 0.9 : (c.trend === 'STABLE' ? 0.7 : 0.5),
    search_demand: c.high_opportunity_keywords && c.high_opportunity_keywords.length > 0 ? 0.85 : 0.6,
    content_gap: 0.75,
    audience_pain_match: c.audience_alignment ? 0.8 : 0.6,
    longevity: c.trend !== 'FALLING' ? 0.8 : 0.4,
    governance_risk: 0.95,
    budget_fit: 0.9
  };

  const weights = {
    trend_strength: 0.15,
    search_demand: 0.20,
    content_gap: 0.15,
    audience_pain_match: 0.20,
    longevity: 0.15,
    governance_risk: 0.10,
    budget_fit: 0.05
  };

  const total_score = Object.entries(scores).reduce((sum, [dim, score]) => sum + (score * weights[dim]), 0);

  return {
    ...c,
    scores: scores,
    total_score: parseFloat(total_score.toFixed(3)),
    shortlist_rank: null
  };
});

scored_candidates.sort((a, b) => b.total_score - a.total_score);
scored_candidates.forEach((c, idx) => { c.shortlist_rank = idx + 1; });

return [{
  json: {
    ...$json,
    scored_candidates: scored_candidates,
    scorecard_ready: true
  }
}];

const scored = $json.scored_candidates || [];
const PROMOTION_THRESHOLD = 0.75;

const promotion_candidates = scored.filter(c => c.total_score >= PROMOTION_THRESHOLD).slice(0, 3);
const top_candidate = promotion_candidates.length > 0 ? promotion_candidates[0] : null;

const scorecard = {
  instance_id: 'TSC-' + Date.now(),
  artifact_family: 'topic_scorecard',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-130-Topic-Scoring',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: scored.length > 0 ? 'CREATED' : 'EMPTY',
  payload: {
    evaluation_count: scored.length,
    promotion_threshold: PROMOTION_THRESHOLD,
    promoted_count: promotion_candidates.length,
    all_evaluated: scored,
    ranked_shortlist: promotion_candidates,
    top_candidate_for_research: top_candidate,
    evaluation_summary: {
      any_above_threshold: promotion_candidates.length > 0,
      ready_for_research_synthesis: promotion_candidates.length > 0,
      needs_broader_discovery: promotion_candidates.length === 0
    }
  }
};

return [{ json: scorecard }];

const scorecard = $json;
const top_topic = scorecard.payload.top_candidate_for_research;

const finalization_packet = {
  instance_id: 'TFP-' + Date.now(),
  artifact_family: 'topic_finalization_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-130-Topic-Scoring',
  dossier_ref: scorecard.dossier_ref,
  created_at: new Date().toISOString(),
  status: top_topic ? 'CREATED' : 'NEEDS_RESEARCH_EXPANSION',
  payload: {
    finalized_topic: top_topic ? top_topic.topic_statement : null,
    topic_confidence: top_topic ? top_topic.total_score : 0,
    research_focus_areas: top_topic ? ['keyword_expansion', 'audience_validation', 'content_gap_analysis'] : [],
    ready_for_research_synthesis: !!top_topic
  }
};

return [{ json: finalization_packet }];

const packet = $json;
const errors = [];

const required_fields = ['instance_id', 'artifact_family', 'schema_version', 'producer_workflow', 'dossier_ref', 'created_at', 'status', 'payload'];
required_fields.forEach(f => { if (packet[f] === undefined || packet[f] === null) errors.push('missing_field:' + f); });

if (packet.artifact_family && packet.artifact_family !== 'topic_finalization_packet') {
  errors.push('wrong_artifact_family:' + packet.artifact_family);
}

if (packet.payload) {
  if (packet.payload.ready_for_research_synthesis === undefined) errors.push('missing_payload_field:ready_for_research_synthesis');
  if (packet.payload.ready_for_research_synthesis === true && !packet.payload.finalized_topic) {
    errors.push('ready_flag_true_but_no_topic');
  }
}

const allowed_status = ['CREATED', 'NEEDS_RESEARCH_EXPANSION', 'EMPTY'];
if (packet.status && !allowed_status.includes(packet.status)) {
  errors.push('invalid_status:' + packet.status);
}

if (errors.length > 0) {
  return [{
    json: {
      validation_status: 'FAILED',
      workflow_id: 'CWF-130',
      packet_id: packet.instance_id || 'UNKNOWN',
      validation_errors: errors,
      escalation_target: 'WF-900',
      escalation_reason: 'packet_schema_validation_failure',
      original_packet: packet
    }
  }];
}

return [{
  json: {
    ...packet,
    validation_status: 'PASSED',
    validated_at: new Date().toISOString(),
    validated_against: 'topic_finalization_packet.schema.json'
  }
}];

return [{
  json: {
    workflow_id: 'CWF-130',
    error_type: 'packet_validation_failure',
    error_source: 'CWF-130-topic-scoring',
    escalation_target: 'WF-900',
    escalation_authority: 'Krishna',
    escalation_path: 'Krishna â†’ Durga â†’ Aruna â†’ WF-900',
    validation_errors: $json.validation_errors || [],
    packet_snapshot: $json.original_packet || {},
    escalated_at: new Date().toISOString()
  }
}];

return [{
  json: {
    workflow_id: 'CWF-130',
    execution_status: 'SUCCESS',
    next_workflow: 'CWF-140',
    scorecard: $json,
    decision: $json.payload.ready_for_research_synthesis ? 'PROCEED_TO_RESEARCH_SYNTHESIS' : 'RETURN_TO_DISCOVERY'
  }
}];
